const resp = $input.item.json || {};
const tracking_date = new Date(Date.now() - 86400000).toISOString().slice(0,10);
// Successful response shape: { data: [{ results: [{ input_tokens, output_tokens, ... }] }] }
if (resp && Array.isArray(resp.data)) {
  let inTokens = 0, outTokens = 0;
  resp.data.forEach(function (bucket) {
    (bucket.results || []).forEach(function (r) {
      inTokens  += parseInt(r.input_tokens)  || 0;
      outTokens += parseInt(r.output_tokens) || 0;
    });
  });
  // Conservative: assume gpt-4o pricing ($2.50 input / $10 output per 1M tokens)
  // → 250 cents in / 1000 cents out per 1M. Adjust if you use different models.
  const costCents = Math.round((inTokens * 250 + outTokens * 1000) / 1000000);
  return { json: { row: { tracking_date, service_name: 'openai', spend_cents: costCents, data_source: 'vendor_api', usage_metrics: { input_tokens: inTokens, output_tokens: outTokens, model_rate_assumed: 'gpt-4o' }, notes: 'Computed via OpenAI organization usage API. Rate assumed gpt-4o; reconcile against monthly invoice for accuracy.' } } };
}
// Fallback: API call failed (no admin key, 401, network) — record $0 with a clear notes string.
const err = resp && resp.error ? (resp.error.message || JSON.stringify(resp.error)) : 'No response';
return { json: { row: { tracking_date, service_name: 'openai', spend_cents: 0, data_source: 'manual', usage_metrics: { fallback: true }, notes: 'OpenAI usage API unavailable (' + err + '). Set OPENAI_ADMIN_API_KEY env var or enter monthly spend manually.' } } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? rows[0] : rows;
return { json: { ok: true, service: 'openai', tracking_date: row.tracking_date, spend_cents: row.spend_cents, data_source: row.data_source, usage: row.usage_metrics } };
